/*
 * Peer-to-Peer Network Node Simulation
 * Demonstrates P2P Computing Environment
 * Each peer can request and share resources
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <pthread.h>

#define MAX_PEERS 10
#define BUFFER_SIZE 256

// Peer structure representing a node in P2P network
typedef struct {
 int peer_id;
 char ip_address[16];
 int port;
 int is_active;
 char shared_files[5][32]; // Files this peer shares
 int file_count;
} Peer;

// Simulated peer database
Peer peers[MAX_PEERS];
int peer_count = 0;
pthread_mutex_t peers_lock = PTHREAD_MUTEX_INITIALIZER;

// Initialize a peer with shared files
void init_peer(Peer *peer, int id, const char *ip, int port, char files[][32], int count) {
 peer->peer_id = id;
 strncpy(peer->ip_address, ip, 15);
 peer->port = port;
 peer->is_active = 1;
 peer->file_count = count;

 for (int i = 0; i < count && i < 5; i++) {
 strncpy(peer->shared_files[i], files[i], 31);
 }
}

// Register peer in network
void register_peer(Peer *peer) {
 pthread_mutex_lock(&peers_lock);
 if (peer_count < MAX_PEERS) {
 peers[peer_count++] = *peer;
 printf("[P2P] Peer %d registered with files: ", peer->peer_id);
 for (int i = 0; i < peer->file_count; i++) {
 printf("%s ", peer->shared_files[i]);
 }
 printf("\n");
 }
 pthread_mutex_unlock(&peers_lock);
}

// Search for a file in the P2P network
int search_file(const char *filename, Peer **found_peer) {
 pthread_mutex_lock(&peers_lock);

 for (int i = 0; i < peer_count; i++) {
 for (int j = 0; j < peers[i].file_count; j++) {
 if (strcmp(peers[i].shared_files[j], filename) == 0) {
 *found_peer = &peers[i];
 pthread_mutex_unlock(&peers_lock);
 return 1; // File found
 }
 }
 }

 pthread_mutex_unlock(&peers_lock);
 return 0; // File not found
}

// Simulate downloading file from peer
void download_file(const char *filename, Peer *source_peer) {
 printf("[P2P] Downloading '%s' from Peer %d (%s:%d)\n",
 filename, 
 source_peer->peer_id,
 source_peer->ip_address,
 source_peer->port);
 printf("[P2P] Download complete! File saved locally.\n");
}

// P2P node behavior: share and request files
void* peer_behavior(void* arg) {
 Peer *peer = (Peer *)arg;

 printf("[*] Peer %d started - IP: %s, Port: %d\n",
 peer->peer_id, peer->ip_address, peer->port);

 // Simulate file sharing (acting as server)
 printf("[P2P] Peer %d is now sharing %d files\n",
 peer->peer_id, peer->file_count);

 // Simulate periodic file requests (acting as client)
 sleep(1);

 // Search for a file in the network
 char search_file[32] = "document.txt";
 Peer *source = NULL;

 if (search_file(search_file, &source)) {
 printf("[P2P] Peer %d found '%s'\n", peer->peer_id, search_file);
 download_file(search_file, source);
 } else {
 printf("[P2P] Peer %d: File '%s' not found in network\n",
 peer->peer_id, search_file);
 }

 return NULL;
}

int main() {
 printf("=== P2P Network Simulation ===\n\n");

 // Create sample peers with shared files
 char files1[][32] = {"video.mp4", "music.mp3"};
 char files2[][32] = {"document.txt", "image.jpg", "data.csv"};
 char files3[][32] = {"document.txt", "report.pdf"};

 Peer peer1, peer2, peer3;

 init_peer(&peer1, 1, "192.168.1.10", 8001, files1, 2);
 init_peer(&peer2, 2, "192.168.1.20", 8002, files2, 3);
 init_peer(&peer3, 3, "192.168.1.30", 8003, files3, 2);

 // Register all peers in network
 register_peer(&peer1);
 register_peer(&peer2);
 register_peer(&peer3);

 printf("\n--- Starting P2P Communication ---\n\n");

 // Simulate peer activities using threads
 pthread_t threads[3];
 pthread_create(&threads[0], NULL, peer_behavior, &peer1);
 pthread_create(&threads[1], NULL, peer_behavior, &peer2);
 pthread_create(&threads[2], NULL, peer_behavior, &peer3);

 // Wait for all threads to complete
 for (int i = 0; i < 3; i++) {
 pthread_join(threads[i], NULL);
 }

 printf("\n=== P2P Simulation Complete ===\n");

 return 0;
}
